{"filesWritten":[{"path":"src/cli/worker.ts","content":"import crypto from 'node:crypto';
import { Worker } from '@temporalio/worker';
import * as activities from './activities';
import type { ActivityInboundCall, ActivityInboundInterceptor, NextFn } from '@temporalio/interceptor';

function logInfo(obj: Record<string, any>): void {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    level: 'info',
    ...obj,
  }));
}

function logError(obj: Record<string, any>): void {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    level: 'error',
    ...obj,
  }));
}

class LoggingActivityInterceptor implements ActivityInboundInterceptor {
  async intercept(activity: ActivityInboundCall, next: NextFn): Promise<unknown> {
    const info = activity.info;
    const workflowExecution = info.workflowExecution;
    logInfo({
      phase: 'activityStart',
      runId: workflowExecution.runId,
      ticketId: workflowExecution.workflowId,
      activityType: info.activityType.name,
      attempt: info.attempt,
    });

    try {
      const result = await next();
      logInfo({
        phase: 'activityComplete',
        runId: workflowExecution.runId,
        ticketId: workflowExecution.workflowId,
        activityType: info.activityType.name,
        attempt: info.attempt,
      });
      return result;
    } catch (error) {
      logError({
        phase: 'activityFailed',
        runId: workflowExecution.runId,
        ticketId: workflowExecution.workflowId,
        activityType: info.activityType.name,
        attempt: info.attempt,
        error: error instanceof Error ? error.message : String(error),
        stack: error instanceof Error ? error.stack : undefined,
      });
      throw error;
    }
  }
}

async function run(): Promise<void> {
  const workerInstanceId = crypto.randomUUID();

  logInfo({ phase: 'workerStart', workerInstanceId });

  const worker = await Worker.create({
    taskQueue: 'default',
    workflowsPath: require.resolve('./workflows'),
    activities,
    interceptors: {
      activities: [new LoggingActivityInterceptor()],
    },
  });

  logInfo({ phase: 'workerReady', workerInstanceId });

  try {
    await worker.run();
    logInfo({ phase: 'workerStop', workerInstanceId });
  } catch (err) {
    logError({
      phase: 'workerFailed',
      workerInstanceId,
      error: err instanceof Error ? err.message : String(err),
    });
    process.exit(1);
  }
}

run().catch((err) => {
  logError({
    phase: 'runFailed',
    error: err instanceof Error ? err.message : String(err),
  });
  process.exit(1);
});"}],"commitMessage":"chore(observability): add structured JSON logging to worker activity boundaries","summary":"Added a Temporal ActivityInboundInterceptor (LoggingActivityInterceptor) that emits structured JSON logs at every activity boundary (start/complete/failed) with required fields: runId (workflowExecution.runId), ticketId (workflowExecution.workflowId), phase, activityType, attempt, and error/stack on failure. Implemented simple JSON lines logger using console.log(JSON.stringify()) with timestamp/level. Also added structured logs for worker lifecycle (start/ready/stop/failed). This directly satisfies the proposal for richer logging in src/cli/worker.ts to ease triage of failed runs. Log format decision: JSON lines (structured, parseable). No metrics or restructuring added (vague 'maybe').","followUps":["Unverified: Add integration test e.g. 'test/worker-logs.test.ts' spawning worker, executing workflow w/ activities (success/fail/retry), assert log lines contain expected fields (runId/ticketId/phase).","Assumption: workflowExecution.workflowId == ticketId (common pattern); if ticketId is a custom field (e.g. SearchAttribute), extract from activity.args[0] or env and update.","Assumption: Temporal SDK >=1.0 supports interceptors & ActivityInboundCall.info shape.","Edge cases addressed: retries (via attempt), failures (error logged+rethrown); unaddressed: heartbeats/timeouts (not in inbound interceptor path) → monitor if needed.","Self-attack: No activities → worker logs only; malformed activityType → stringifies; high volume → console perf ok short-term.","Consider pino for prod perf if console bottleneck.","Future: Add metrics per tasks.md if prioritized."]}
